"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[6882],{95650(e,n,i){i.r(n),i.d(n,{assets:()=>d,contentTitle:()=>a,default:()=>o,frontMatter:()=>u,metadata:()=>r,toc:()=>l});const r=JSON.parse('{"id":"learning/courses/quantum-business-foundations/quantum-technology","title":"Quantentechnologie","description":"Erkenne, dass die L\xf6sung bedeutsamer Probleme eine Kombination aus Quanten- und klassischen Ressourcen erfordert.","source":"@site/i18n/de/docusaurus-plugin-content-docs/current/learning/courses/quantum-business-foundations/quantum-technology.mdx","sourceDirName":"learning/courses/quantum-business-foundations","slug":"/learning/courses/quantum-business-foundations/quantum-technology","permalink":"/learning/courses/quantum-business-foundations/quantum-technology","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-business-foundations/quantum-technology.mdx","tags":[],"version":"current","frontMatter":{"title":"Quantentechnologie","description":"Erkenne, dass die L\xf6sung bedeutsamer Probleme eine Kombination aus Quanten- und klassischen Ressourcen erfordert."},"sidebar":"tutorialsSidebar","previous":{"title":"Grundlagen des Quantencomputings","permalink":"/learning/courses/quantum-business-foundations/quantum-computing-fundamentals"},"next":{"title":"Gesch\xe4ftliche Auswirkungen","permalink":"/learning/courses/quantum-business-foundations/business-impacts"}}');var t=i(74848),s=i(28453);const u={title:"Quantentechnologie",description:"Erkenne, dass die L\xf6sung bedeutsamer Probleme eine Kombination aus Quanten- und klassischen Ressourcen erfordert."},a="IBM Quantentechnologie {#ibm-quantum-technology}",d={},l=[{value:"Lernziele",id:"learning-objectives",level:2},{value:"IBM Quantum Platform",id:"ibm-quantum-platform",level:3},{value:"Qiskit Runtime",id:"qiskit-runtime",level:3},{value:"IBM supraleitende Quantencomputer",id:"ibm-superconducting-quantum-computers",level:3},{value:"Leistung von Quantencomputern",id:"quantum-computing-performance",level:2},{value:"Messung der Leistung von Quantencomputern",id:"measuring-quantum-computing-performance",level:3},{value:"Wissen \xfcberpr\xfcfen",id:"check-your-understanding",level:3},{value:"Was als N\xe4chstes im Quantencomputing kommt",id:"whats-next-in-quantum-computing",level:2},{value:"Quantum Utility",id:"quantum-utility",level:3},{value:"Fehlerkorrektur",id:"error-correction",level:3},{value:"IBM Quantum Entwicklungs-Roadmap",id:"ibm-quantum-development-roadmap",level:3},{value:"5k-Herausforderung",id:"5k-challenge",level:3},{value:"Quantenzentrierte Supercomputer",id:"quantum-centric-supercomputers",level:3},{value:"Wichtige Erkenntnisse",id:"key-takeaways",level:2}];function h(e){const n={a:"a",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",img:"img",li:"li",p:"p",strong:"strong",ul:"ul",...(0,s.R)(),...e.components},{Details:r,IBMVideo:u}=n;return r||c("Details",!0),u||c("IBMVideo",!0),(0,t.jsxs)(t.Fragment,{children:["\n","\n",(0,t.jsx)(n.header,{children:(0,t.jsx)(n.h1,{id:"ibm-quantum-technology",children:"IBM Quantentechnologie"})}),"\n",(0,t.jsx)(n.p,{children:"Die Flotte der IBM\xae-Quantencomputer \u2013 alle mit mindestens 127 Qubits \u2013 ist die gr\xf6\xdfte der Welt. Diese Quantencomputer verwenden supraleitende Transmon-Qubits, die zwar nicht die einzige Art von Qubits sind, aber viele Vorteile bieten. Die Kombination unserer erstklassigen Quantencomputer mit Qiskit erm\xf6glicht es unseren Nutzern, heute schon zu erforschen, wie Quantencomputing in der Praxis n\xfctzlich sein kann. Branchenpartner und Forscher nutzen IBM Quantum\xae-Technologie, um bedeutsame Berechnungen und realistische Anwendungen zu erkunden. Lass uns die Breite der Programme und Dienste erkunden, die IBM Quantum seinen Partnern anbietet."}),"\n",(0,t.jsx)(n.p,{children:"Wenn du einer Institution angeh\xf6rst, die Mitglied des IBM Quantum Network ist, wende dich an die Quantencomputing-Gruppe deiner Institution, um herauszufinden, welche Vorteile dir zur Verf\xfcgung stehen."}),"\n",(0,t.jsx)(n.h2,{id:"learning-objectives",children:"Lernziele"}),"\n",(0,t.jsx)(n.p,{children:"Am Ende dieses Moduls solltest du in der Lage sein:"}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsx)(n.li,{children:"Zu erkennen, dass die L\xf6sung bedeutsamer Probleme eine Kombination aus Quanten- und klassischen Ressourcen erfordert."}),"\n",(0,t.jsx)(n.li,{children:"Die verf\xfcgbare Hardware, Software und Dienste zur L\xf6sung bedeutsamer Probleme zu identifizieren."}),"\n",(0,t.jsx)(n.li,{children:"Zu beschreiben, wie die Leistung von Quantencomputern gemessen wird, einschlie\xdflich Skalierung, Qualit\xe4t und Geschwindigkeit."}),"\n"]}),"\n",(0,t.jsx)(n.h3,{id:"ibm-quantum-platform",children:"IBM Quantum Platform"}),"\n",(0,t.jsx)(n.p,{children:"Die IBM Quantum Platform bietet eine Suite von Quantencomputing-Tools, die alle f\xfcr die Arbeit ben\xf6tigten Forschungs- und Entwicklungsressourcen an einem Ort b\xfcndelt. Nutzer k\xf6nnen ein Konto anlegen und sich anmelden, um Zugang zu IBM-Quantencomputern zu erhalten, Computerdetails einzusehen, Workloads zu verfolgen und in der Dokumentation und im Learning-Bereich auf Lernmaterialien zuzugreifen."}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsxs)(n.li,{children:["Die ",(0,t.jsx)(n.a,{href:"https://quantum.cloud.ibm.com/",children:"Startseite"})," dient als prim\xe4rer Ausgangspunkt f\xfcr das Produkt\xf6kosystem, wo Nutzer ihre API-Schl\xfcssel abrufen, eine \xdcbersicht \xfcber ihre Instanzen und Nutzungsinformationen einsehen, aktuelle Job-Details abrufen und auf hilfreiche Links zu anderen Bereichen der Plattform zugreifen k\xf6nnen."]}),"\n",(0,t.jsxs)(n.li,{children:["Die ",(0,t.jsx)(n.a,{href:"/docs",children:"Dokumentation"})," fasst Qiskit-Dokumentation, Service-Dokumentation und API-Referenzinformationen an einem Ort zusammen, geordnet nach nat\xfcrlichen Arbeitsabl\xe4ufen der Nutzer."]}),"\n",(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.a,{href:"/learning",children:"Learning"})," ist die Heimat f\xfcr Lernmaterialien, einschlie\xdflich Kursen und Lehrmodulen sowie dem interaktiven Circuit Composer (demn\xe4chst verf\xfcgbar). Dieser kombinierte grafische und Code-Editor erm\xf6glicht es Nutzern, Circuits visuell zu prototypisieren, zu simulieren und zu debuggen und sie anschlie\xdfend auf IBM-Quantencomputern auszuf\xfchren."]}),"\n"]}),"\n",(0,t.jsx)(n.h3,{id:"qiskit-runtime",children:"Qiskit Runtime"}),"\n",(0,t.jsx)(n.p,{children:"Qiskit Runtime ist eine portable, sichere, containerisierte Architektur, die Quantenprogramme auf einer klassischen Recheneinheit ausf\xfchrt, die eng mit dem Quantenprozessor integriert ist. Qiskit Runtime erm\xf6glicht es dem Quantencomputer, Teil jeder Rechenumgebung zu werden und Berechnungen zu beschleunigen \u2013 \xe4hnlich wie eine Grafikprozessoreinheit (GPU) \u2013 und \xfcbernimmt die Job-Orchestrierung und den Datentransfer zur Quantenverarbeitungseinheit, um die Effizienz zu maximieren."}),"\n",(0,t.jsx)(n.p,{children:"Qiskit und Qiskit Runtime vereinfachen die schnelle Orchestrierung von Programmen \xfcber Rechenressourcen in der Cloud. IBM entwickelt Middleware f\xfcr Quantencomputing, um die Leistung von Quantenanwendungen zu maximieren, die auf parallelisierten, cloudbasierten Quanten- und klassischen Rechenressourcen laufen. Diese Middleware umfasst das Circuit Knitting Toolbox und unsere Quantum Serverless-Architektur."}),"\n",(0,t.jsxs)(n.p,{children:["Das ",(0,t.jsx)(n.a,{href:"https://docs.quantum.ibm.com/api/qiskit-addon-cutting",children:"Circuit Cutting Qiskit Addon"})," erm\xf6glicht es Entwicklern, gro\xdfe Circuits in kleinere Circuits zu zerschneiden, die f\xfcr aktuelle Quantencomputer geeignet sind. Circuit Knitting nutzt klassische Berechnungen, um einen Teil der Rechenlast eines Quantum Circuits zu \xfcbernehmen und so \xfcber das hinaus zu gehen, was allein mit Quanten- oder klassischen Computern erreichbar ist. Zus\xe4tzliche Tools helfen dabei, Circuits mit klassischen Ressourcen zu rekonstruieren und Endergebnisse zusammenzuf\xfcgen."]}),"\n",(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.a,{href:"/guides/serverless",children:"Quantum Serverless"})," ist ein Multi-Cloud-Orchestrierungs-Toolkit, das elastische klassische Ressourcen mit dem IBM Qiskit Runtime-Dienst verbindet. Quantum Serverless erm\xf6glicht es Entwicklern, sich auf den Code zu konzentrieren statt auf die Ressourcenbereitstellung."]}),"\n",(0,t.jsx)(n.h3,{id:"ibm-superconducting-quantum-computers",children:"IBM supraleitende Quantencomputer"}),"\n",(0,t.jsxs)(n.p,{children:["IBM-Quantenprozessoren verwenden einen physischen Qubit-Typ namens ",(0,t.jsx)(n.strong,{children:"supraleitender Transmon-Qubit"}),", der aus supraleitenden Materialien besteht, die auf einem Siliziumsubstrat strukturiert sind. Andere Quantenprozessoren k\xf6nnten photonische Qubits verwenden, die aus einzelnen Lichtphotonen bestehen, oder gefangene Ionen-Qubits, die Informationen in geladenen Atompartikeln speichern. Um den Fluss elektrischer Str\xf6me zu erm\xf6glichen, m\xfcssen supraleitende Qubits bei extrem niedrigen Temperaturen gehalten werden \u2013 nahe dem absoluten Nullpunkt."]}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"IBM 127-qubit processor",src:i(60794).A+"",width:"450",height:"450"})}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.em,{children:"IBM 127-Qubit-Prozessor"})}),"\n",(0,t.jsx)(n.h2,{id:"quantum-computing-performance",children:"Leistung von Quantencomputern"}),"\n",(0,t.jsx)(n.h3,{id:"measuring-quantum-computing-performance",children:"Messung der Leistung von Quantencomputern"}),"\n",(0,t.jsx)(n.p,{children:"Ein universell fehlertoleranter Quantencomputer ist die gro\xdfe Herausforderung des Quantencomputings. Es handelt sich um ein Ger\xe4t, das universelle Quantenoperationen mit unzuverl\xe4ssigen Komponenten korrekt durchf\xfchren kann. Die heutigen Quantencomputer sind nicht fehlertolerant."}),"\n",(0,t.jsx)(n.p,{children:"Um Quantencomputer miteinander zu vergleichen, reicht die Anzahl der Qubits nicht aus. Viele weitere Details m\xfcssen ber\xfccksichtigt werden, beispielsweise Fehlerraten und wie das System verdrahtet ist. Es gibt vier Schl\xfcsselmetriken zur Messung der Quantencomputer-Leistung:"}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:"Skalierung"})," \u2013 Gemessen an der ",(0,t.jsx)(n.strong,{children:"Anzahl der Qubits"}),", was die Menge der Informationen angibt, die wir im Quantencomputer kodieren k\xf6nnen."]}),"\n",(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:"Qualit\xe4t"})," \u2013 Gemessen am ",(0,t.jsx)(n.strong,{children:"Quantum Volume"}),", das die Qualit\xe4t der Circuits und die Genauigkeit der Implementierung von Circuits in Hardware angibt."]}),"\n",(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:"Geschwindigkeit"})," \u2013 Gemessen an ",(0,t.jsx)(n.strong,{children:"CLOPS (Circuit Layer Operations Per Second)"}),", das angibt, wie viele Circuits in einer bestimmten Zeit auf der Hardware ausgef\xfchrt werden k\xf6nnen."]}),"\n",(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:"Layer-Treue"})," \u2013 Gemessen an ",(0,t.jsx)(n.strong,{children:"EPLG (Errors Per Layered Gate)"}),", das beschreibt, wie Fehler auftreten, wenn Operationen auf Qubits ausgef\xfchrt werden."]}),"\n"]}),"\n",(0,t.jsxs)(n.p,{children:["Eine detailliertere Beschreibung einiger der oben genannten Metriken findest du in ",(0,t.jsx)(n.a,{href:"https://research.ibm.com/blog/quantum-metric-layer-fidelity",children:"diesem Artikel"})," im IBM Research Blog. Jede Phase der Einf\xfchrung von Quantencomputing in der Industrie wird durch zunehmendes Quantum Volume vorangetrieben, das anhand verschiedener Parameter wie Circuit-Breite, Qubit-Konnektivit\xe4t und Fehlerraten berechnet wird."]}),"\n",(0,t.jsx)(n.p,{children:"Die technische Definition des Quantum Volume l\xe4sst sich ohne Gleichungen schwer vermitteln.\nDario Gil, Direktor f\xfcr Forschung bei IBM, erkl\xe4rt:"}),"\n",(0,t.jsx)(u,{id:"133345140",title:"Dario Gil explains the concept of quantum volume. In particular he explains how and why it depends on both qubit count and error rates."}),"\n",(0,t.jsx)(n.p,{children:"Um das Quantum Volume besser zu verstehen, betrachte folgende anschauliche Analogie. Der nachfolgende Abschnitt behandelt Zeit, Raum und Fehlerraten am Beispiel einer Stadtbesichtigung in New York."}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.strong,{children:"Die Zust\xe4nde des Quantum Volume auf Reisen"})}),"\n",(0,t.jsxs)(n.p,{children:["Das Quantum Volume beschreibt den gr\xf6\xdften Quantenberechnungsraum, den ein Quantencomputer erkunden kann, wobei das Volumen des Quantenraums 2",(0,t.jsx)("sup",{children:"N"}),' betr\xe4gt, mit N als Anzahl der Qubits, also der \xfcblichen Zustandsraumdimension. Wir verwenden bewusst das Wort \u201eRaum", denn sobald wir von Raum sprechen, liegt es nahe, auch an ein Volumen zu denken.']}),"\n",(0,t.jsx)(n.p,{children:"Der Faktor, der diese Erkundung begrenzt, ist die Fehlerrate. Die Fehlerrate kann mit der Zeit gleichgesetzt werden, die wir zur Erkundung des Raums haben. Mehr Fehler bedeuten weniger Zeit zum Erkunden. Je gr\xf6\xdfer der Rechenraum ist, desto mehr Zeit braucht man, ihn vollst\xe4ndig zu erkunden \u2013 daher brauchen wir einen Quantencomputer mit einer geringeren Fehlerrate."}),"\n",(0,t.jsx)(n.p,{children:"Stell dir eine Touristin vor, die New York City erkundet. Sie m\xf6chte die gesamte Stadt besichtigen, das hei\xdft, sie strebt nach einem Touristenvolumen in der Gr\xf6\xdfe von NYC. Wenn wir ihr nur einen Tag geben, gibt es keine M\xf6glichkeit, so viel Raum zu erkunden \u2013 das gew\xfcnschte Touristenvolumen wird nicht erreicht. Wenn wir ihr jedoch drei Tage geben, kann sie wahrscheinlich alle Top-Sehensw\xfcrdigkeiten besuchen und das ben\xf6tigte Touristenvolumen von NYC erreichen."}),"\n",(0,t.jsx)(n.p,{children:"Was aber, wenn wir der Touristin mehr Zeit geben, aber den Raum weiterhin auf NYC beschr\xe4nken? Anders ausgedr\xfcckt: Was wenn wir die Anzahl der Qubits gleich lassen, aber die Fehlerrate senken? Dann n\xfctzt es der Touristin nichts, denn sie hat die Stadt bereits erkundet und besucht nur noch dieselben Orte immer wieder. Das Touristenvolumen bleibt gleich. Bei mehr Zeit ist es stattdessen sinnvoller, die Anzahl der zu besuchenden Touristenattraktionen zu erh\xf6hen."}),"\n",(0,t.jsx)(n.p,{children:"Oder stell dir vor, wir lassen die Zeit auf drei Tage festgelegt, aber die Touristin versucht, ganz NYC und Long Island zu erkunden. Anders gesagt: Was wenn wir die Fehlerrate festhalten, aber mehr Qubits hinzuf\xfcgen? Auch dann bleibt das Touristenvolumen auf NYC beschr\xe4nkt, da die Touristin den gr\xf6\xdferen Raum in der verf\xfcgbaren Zeit nicht erkunden kann. Um eine bessere Touristin zu sein und ein gr\xf6\xdferes Touristenvolumen zu erreichen, muss man gleichzeitig den Erkundungsraum vergr\xf6\xdfern und die zur Verf\xfcgung stehende Zeit erh\xf6hen."}),"\n",(0,t.jsx)(n.p,{children:"Genauso erfordert das Bauen besserer Quantencomputer mit gr\xf6\xdferem Quantum Volume gleichzeitig die Vergr\xf6\xdferung des Quantenberechnungsraums (Anzahl der Qubits) und die Senkung der Fehlerrate (Verl\xe4ngerung der Zeit, in der der Algorithmus laufen kann). Beispielsweise hat IBM durch Fortschritte bei abstimmbaren Kopplungsarchitekturen das Quantum Volume in nur einem Jahr gleich zweimal verdoppelt!"}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"Quantum Volume",src:i(45223).A+"",width:"720",height:"405"})}),"\n",(0,t.jsx)(n.p,{children:"Mit der Weiterentwicklung des Quantencomputings r\xfcckt jedoch die n\xfctzliche Arbeit, die unsere Quantencomputer in einer angemessenen Zeit verrichten k\xf6nnen, st\xe4rker in den Fokus. Wenn wir Skalierung an der Anzahl der Qubits und Qualit\xe4t am Quantum Volume messen, dann ist die Quantenverarbeitungsgeschwindigkeit das Ma\xdf f\xfcr die n\xfctzliche Arbeit, die diese Qubits in angemessener Zeit leisten k\xf6nnen. Wir definieren sie als die Anzahl primitiver Circuits, die pro Sekunde verarbeitet werden k\xf6nnen. Sie \xe4hnelt FLOPS im klassischen Computing \u2013 der Anzahl von Gleitkommaoperationen pro Sekunde. Die Verbesserung der QPU-Geschwindigkeit ist der Schl\xfcssel zum praktischen Quantencomputing. Wie bei der klassischen Computerprogrammierung erfordert Quantenprogrammierung das Ausf\xfchren vieler Circuits. Eine vern\xfcnftige QPU-Geschwindigkeit erm\xf6glicht es Nutzern, Quantencomputing in ihre Arbeitsabl\xe4ufe zu integrieren."}),"\n",(0,t.jsx)(n.h3,{id:"check-your-understanding",children:"Wissen \xfcberpr\xfcfen"}),"\n",(0,t.jsx)(n.p,{children:"Lies die folgende Frage, denke \xfcber deine Antwort nach und klicke dann auf das Dreieck, um die L\xf6sung anzuzeigen."}),"\n",(0,t.jsxs)(r,{children:[(0,t.jsx)("summary",{children:(0,t.jsx)(n.p,{children:"Richtig oder falsch: Das Quantum Volume bezieht sich auf die Gr\xf6\xdfe der Kryok\xfchlschr\xe4nke, in denen IBM-Quantencomputer untergebracht sind."})}),(0,t.jsx)(n.p,{children:"Falsch. Das Quantum Volume ist eine einzelne Zahl, die die Leistung heutiger Quantencomputer zusammenfassen soll."})]}),"\n",(0,t.jsx)(n.h2,{id:"whats-next-in-quantum-computing",children:"Was als N\xe4chstes im Quantencomputing kommt"}),"\n",(0,t.jsx)(n.p,{children:"Die heutigen Quantencomputer \u2013 und die, die in absehbarer Zukunft erwartet werden \u2013 sind verrauscht. Das bedeutet, sie reagieren empfindlich auf Umweltst\xf6rungen, die die Genauigkeit der Ergebnisse beeinflussen k\xf6nnen. \xc4hnlich wie sich das klassische Computing durch modulare Skalierung von Prozessoren, effiziente Berechnung und Parallelisierung weiterentwickelt hat, sehen wir das Quantencomputing auf dem Weg, sein volles Potenzial zu entfalten. Auf dem Weg zu vollst\xe4ndig fehlertoleranten Quantencomputern wollen wir n\xfctzliche Probleme mit der Hardware und Software l\xf6sen, die wir heute besitzen."}),"\n",(0,t.jsx)(n.h3,{id:"quantum-utility",children:"Quantum Utility"}),"\n",(0,t.jsx)(n.p,{children:"IBM Quantum und die University of California, Berkeley pr\xe4sentierten Belege daf\xfcr, dass Quantencomputer dank Fortschritten bei IBM Quantum-Hardware und Fehlerminderungsmethoden fr\xfcher als erwartet Mehrwert liefern k\xf6nnen. \xdcber einen blo\xdfen Machbarkeitsnachweis hinaus haben wir Ergebnisse erzielt, die genau genug sind, um n\xfctzlich zu sein. Das Berechnungsmodell, das wir bei dieser Arbeit erkundet haben, ist ein zentraler Bestandteil vieler Algorithmen, die f\xfcr kurzfristige Quantencomputer konzipiert sind."}),"\n",(0,t.jsx)(n.p,{children:"Die R\xfcckkopplungsschleife zwischen Quanten- und klassischen Computern ist entscheidend f\xfcr den Fortschritt der Quantentechnologien. Mit einem Fokus auf Quantum Utility nutzen wir Quantencomputing, um komplexe Probleme zu untersuchen, die bestehende High-Performance-Computing-Frameworks herausfordern, und \xfcberpr\xfcfen die Ergebnisse klassisch. Dieses st\xe4ndige Wechselspiel zwischen Quantencomputing, das komplexe Circuits ausf\xfchrt, und klassischen Computern, die die Quantenergebnisse verifizieren, wird beide Rechenbereiche verbessern und Nutzern Vertrauen in die F\xe4higkeiten kurzfristiger Quantencomputer geben."}),"\n",(0,t.jsx)(u,{id:"134056420",title:"This video outlines how noisy quantum computers use error mitigation to out-perform brute force classical methods on an example problem."}),"\n",(0,t.jsxs)(r,{children:[(0,t.jsx)("summary",{children:(0,t.jsx)(n.p,{children:"Optionale Lekt\xfcre \u2013 klicke auf das Dreieck, um mehr \xfcber das Experiment zu erfahren"})}),(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsx)(n.p,{children:"In diesem Experiment haben wir alle 127 Qubits unseres IBM Quantum Eagle-Prozessors genutzt, um das sich ver\xe4ndernde Verhalten eines Systems zu simulieren, das sich nat\xfcrlich auf einen Quantencomputer abbilden l\xe4sst: das Quanten-Ising-Modell. Ising-Modelle sind Vereinfachungen der Natur, die wechselwirkende Atome als Gitter wechselwirkender Quanten-Zwei-Zustands-Systeme in einem Energiefeld darstellen. Diese Systeme \xe4hneln stark den zwei-Zustands-Qubits, aus denen unsere Quantencomputer bestehen, und eignen sich daher gut f\xfcr den Test unserer Methoden. Wir verwendeten ZNE, um eine Eigenschaft des Systems namens Erwartungswert \u2013 im Wesentlichen ein gewichteter Durchschnitt der m\xf6glichen Ergebnisse des Circuits \u2013 m\xf6glichst genau zu berechnen."}),"\n"]}),"\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsx)(n.p,{children:"Gleichzeitig versuchte das Berkeley-Team, dasselbe System mithilfe von Tensornetzwerk-Methoden mit Hilfe fortschrittlicher Supercomputer am National Energy Research Scientific Computing Center (NERSC) des Lawrence Berkeley National Lab und an der Purdue University zu simulieren."}),"\n"]}),"\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsx)(n.p,{children:"Die Quantenmethoden stimmten weiterhin mit den exakten Methoden \xfcberein. Schlie\xdflich begannen die klassischen N\xe4herungsmethoden jedoch zu versagen, als der Schwierigkeitsgrad erh\xf6ht wurde."}),"\n"]}),"\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsx)(n.p,{children:"Schlie\xdflich baten wir beide Computer, Berechnungen durchzuf\xfchren, die \xfcber das exakt Berechenbare hinausgingen \u2013 und der Quantencomputer lieferte eine Antwort, der wir gr\xf6\xdferes Vertrauen entgegenbrachten. Obwohl wir nicht beweisen konnten, ob diese Antwort tats\xe4chlich korrekt war, gaben uns Eagles Erfolge bei den vorherigen Durchl\xe4ufen des Experiments das Vertrauen, dass sie es waren."}),"\n"]}),"\n"]})]}),"\n",(0,t.jsx)(n.h3,{id:"error-correction",children:"Fehlerkorrektur"}),"\n",(0,t.jsx)(n.p,{children:"Fehlerkorrektur ist seit Jahrzehnten ein wichtiger Forschungsbereich. Aber die meiste Zeit waren theoretische Fehlerkorrekturtechniken auf echten Quantencomputern nicht praktisch umsetzbar, meist wegen der sehr gro\xdfen Anzahl ben\xf6tigter Qubits. Tats\xe4chlich sagen viele Experten voraus, dass praktisches fehlertolerantes Quantencomputing (FTQC) Millionen physikalischer Qubits erfordern wird. In einem k\xfcrzlich auf dem Cover von Nature ver\xf6ffentlichten Artikel haben Forscher von IBM jedoch einen neuen Code eingef\xfchrt, den wir Gross-Code nennen, der diese Einschr\xe4nkung \xfcberwindet."}),"\n",(0,t.jsxs)(n.p,{children:["Das Papier ",(0,t.jsx)(n.a,{href:"https://www.nature.com/articles/s41586-024-07107-7",children:"High-threshold and low-overhead fault-tolerant quantum memory"})," beschreibt den neuen Quantenfehlerkorrektur-Code, der etwa zehnmal effizienter als bisherige Methoden beim Schutz empfindlicher Quantendaten vor Fehleransammlungen ist. Um zu verstehen, wie viel n\xe4her wir dem Beginn der Fehlerkorrektur nun sind: Mit dem Gross-Code kann man 12 logische Qubits f\xfcr ungef\xe4hr eine Million Zyklen von Fehlerpr\xfcfungen mit 288 Qubits sch\xfctzen."]}),"\n",(0,t.jsx)(n.p,{children:"Es wird nicht erwartet, dass Fehlerkorrektur pl\xf6tzlich Fehlerminderung und Fehlerunterdr\xfcckung ersetzen wird. Vielmehr werden Fehlerminderung und -unterdr\xfcckung in den n\xe4chsten Jahren weiterhin eine entscheidende Rolle spielen, w\xe4hrend gleichzeitig die Anzahl der fehlerkorrigierten Qubits zunimmt."}),"\n",(0,t.jsx)(n.h3,{id:"ibm-quantum-development-roadmap",children:"IBM Quantum Entwicklungs-Roadmap"}),"\n",(0,t.jsx)(n.p,{children:"Wir befinden uns nun fest in der \xc4ra der Quantum Utility. Das bedeutet, dass Quantencomputer besser im Quantencomputing sind als klassische Computer und von unseren Nutzern genutzt werden k\xf6nnen, um neue Algorithmen zu entdecken und nach Quantenvorteilen zu suchen. Unsere Roadmap skizziert unsere historischen Meilensteine und Pl\xe4ne, bis 2026 einen kurzfristigen Quantenvorteil zu erreichen."}),"\n",(0,t.jsxs)(n.p,{children:["Bis 2029 werden wir Starling liefern \u2013 einen gro\xdfformatigen fehlertoleranten Quantencomputer, der Quanten-Circuits mit 100 Millionen Quantengattern auf 200 logischen Qubits ausf\xfchren kann. Wir bauen dieses System gerade in unserem historischen Werk in Poughkeepsie, New York. Erfahre mehr \xfcber unseren Fortschritt in der ",(0,t.jsx)(n.a,{href:"http://www.ibm.com/downloads/documents/us-en/131cf87ab63319bf",children:"Guided Roadmap PDF."})]}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"Development Roadmap",src:i(80305).A+"",width:"1920",height:"1080"})}),"\n",(0,t.jsxs)(n.p,{children:["Lies mehr \xfcber die IBM Quantum Entwicklungs-Roadmap ",(0,t.jsx)(n.a,{href:"https://www.ibm.com/quantum/roadmap",children:"hier"}),"."]}),"\n",(0,t.jsx)(n.h3,{id:"5k-challenge",children:"5k-Herausforderung"}),"\n",(0,t.jsx)(n.p,{children:'IBM arbeitet gemeinsam mit der Quantenforschungsgemeinschaft daran, potenzielle Anwendungsf\xe4lle zu finden, die von Quantencomputing profitieren k\xf6nnten. Wir stellen zunehmend leistungsf\xe4higere Tools zur Verf\xfcgung, damit Nutzer dr\xe4ngende Probleme mit Quantencomputing angehen k\xf6nnen. Im Jahr 2024 ver\xf6ffentlichten wir ein Tool, das unverzerrte Observablen langer, hochqualitativer Circuits berechnen kann. Die Suche nach dem, was sich mit dieser Kombination aus 100+ Qubits und tiefen Circuits tun l\xe4sst, wurde einst als \u201e100x100-Herausforderung" bezeichnet. Aber die genaue Anzahl der Qubits und die Tiefe bei jedem sind weniger wichtig als die Nutzung der kombinierten St\xe4rke. Stell dir vor, was mit 5.000 Quantum-Circuits in einer einzigen Berechnung m\xf6glich ist. \u200bNutzer k\xf6nnen Quantum-Circuits mit Komplexit\xe4t und Laufzeit ausf\xfchren, die die F\xe4higkeiten der besten klassischen Computer von heute \xfcbersteigen. Wir sind gespannt, was die Quantencommunity entwickeln wird, um die M\xf6glichkeiten des Quantencomputings zu nutzen und wichtige Probleme zu l\xf6sen.'}),"\n",(0,t.jsx)(n.h3,{id:"quantum-centric-supercomputers",children:"Quantenzentrierte Supercomputer"}),"\n",(0,t.jsx)(n.p,{children:"Der Schl\xfcssel zur L\xf6sung von Problemen in gro\xdfem Ma\xdfstab liegt darin, \xfcber einzelne Chip-Prozessoren hinaus zu gehen. Im Jahr 2024 stellten wir Crossbill vor \u2013 den ersten Einzelprozessor aus mehreren Chips. Das sind die ersten Schritte in eine neue \xc4ra der Skalierung und bieten einen klaren Weg zu 100.000 Qubits und dar\xfcber hinaus mit quantenzentriertem Supercomputing. Dies ist eine modulare Computerarchitektur, die Skalierung erm\xf6glicht. Sie kombiniert Quantenkommunikation und -berechnung, um die Rechenkapazit\xe4t zu erh\xf6hen, w\xe4hrend Hybrid-Cloud-Middleware eine nahtlose Integration von Quanten- und klassischen Arbeitsabl\xe4ufen erm\xf6glicht."}),"\n",(0,t.jsx)(n.p,{children:"Die L\xf6sung der komplexesten Probleme der Welt wird eine Kombination aus klassischen und Quantenressourcen erfordern. Dar\xfcber hinaus wird sie von der kontinuierlichen Zusammenarbeit zwischen Industrie und Wissenschaft abh\xe4ngen."}),"\n",(0,t.jsx)(n.h2,{id:"key-takeaways",children:"Wichtige Erkenntnisse"}),"\n",(0,t.jsx)(n.p,{children:"Diese Erkenntnisse solltest du im Hinterkopf behalten:"}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsx)(n.li,{children:"Die heutigen Quantencomputer sind nicht fehlertolerant."}),"\n",(0,t.jsx)(n.li,{children:"Das Quantum Volume ist ein ganzheitliches Ma\xdf daf\xfcr, wie gut ein Quantencomputer ist. Je h\xf6her das Quantum Volume, desto besser. Nur \xfcber die Qubit-Anzahl zu sprechen ist irref\xfchrend."}),"\n",(0,t.jsx)(n.li,{children:"Zur Messung der Leistung von Quantencomputern gibt es vier Schl\xfcsselmetriken: Skalierung, Qualit\xe4t, Geschwindigkeit und Layer-Treue."}),"\n",(0,t.jsx)(n.li,{children:"Ein gemeinsames Experiment von IBM Quantum und UC Berkeley lieferte Belege daf\xfcr, dass IBM-Quantencomputer bei anspruchsvollen Simulationsproblemen mit 127 Qubits zuverl\xe4ssige und genaue Ergebnisse liefern."}),"\n",(0,t.jsx)(n.li,{children:"Quantenzentriertes Supercomputing bedeutet, Quantencomputing als Teil eines umfassenderen HPC-Paradigmas zu behandeln, bei dem klassische und Quantencomputer als eine einzige Recheneinheit zusammenarbeiten."}),"\n"]})]})}function o(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(h,{...e})}):h(e)}function c(e,n){throw new Error("Expected "+(n?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}},60794(e,n,i){i.d(n,{A:()=>r});const r=i.p+"assets/images/127qubit-processer-5f4e07dd161a5396ac24b1af43f9999a.avif"},80305(e,n,i){i.d(n,{A:()=>r});const r=i.p+"assets/images/IBM-Quantum-Development-and-Innovation-Roadmap-2025-f5804f9bec56cfc9744c8755f6d3a0a5.svg"},45223(e,n,i){i.d(n,{A:()=>r});const r=i.p+"assets/images/QV-ae503518346a4890c4c69e31ee36ea27.avif"},28453(e,n,i){i.d(n,{R:()=>u,x:()=>a});var r=i(96540);const t={},s=r.createContext(t);function u(e){const n=r.useContext(s);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(t):e.components||t:u(e.components),r.createElement(s.Provider,{value:n},e.children)}}}]);